mapper.select:
SELECT su.user_id, su.user_name, su.nick_name, su.email, su.phonenumber, su.status, su.create_time, sud.id as user_duty_id FROM sys_user su JOIN sys_user_duty sud on su.user_id = sud.user_id and sud.duty_id = #{dutyId}
AND su.user_name like concat('%', #{param.userName}, '%')
AND su.phonenumber like concat('%', #{param.phonenumber}, '%')

SELECT su.user_id, su.user_name, su.nick_name, su.email, su.phonenumber, su.status, su.create_time
FROM sys_user su
JOIN sys_user_org suo ON su.user_id = suo.user_id AND suo.org_id = #{orgId}
WHERE
su.user_id not in (
select sud.user_id from sys_user_duty sud WHERE sud.duty_id = #{dutyId}
)

    AND su.user_name like concat('%', #{param.userName}, '%')


    AND su.phonenumber like concat('%', #{param.phonenumber}, '%')

SELECT sd.*, sud.id as userDutyId
FROM sys_duty sd
         JOIN sys_user_duty sud on sd.id = sud.duty_id and sud.user_id = #{userId}
WHERE sd.org_id = #{orgId}

SELECT sd.duty_name
FROM sys_duty sd
         JOIN sys_user_duty sud on sd.id = sud.duty_id and sud.user_id = #{userId}
WHERE sd.org_id = #{orgId}
